    "low": 10,
    "below_normal": 5,
    "normal": 0,
    "above_normal": -5,
    "high": -10,
}

# Mapping of the public priority names to Windows priority classes. The
# numeric values match the ``*_PRIORITY_CLASS`` constants from the Win32
# API so they can be used even on non-Windows platforms without importing
