def _set_process_priority(self, pid: int) -> None:
    """Best-effort attempt to set the priority of the editor process
    on Unix-like systems. Windows priority is instead applied via
    ``creationflags`` when the process is spawned.

    Any failure (unsupported platform, insufficient permissions,
    unknown priority value, etc.) is silently ignored so that the
    edit operation always proceeds.
    """
    nice_value = _NICE_VALUES.get(self.process_priority)  # type: ignore[arg-type]
    if nice_value is None:
        return
    try:
        os.setpriority(os.PRIO_PROCESS, pid, nice_value)
    except (AttributeError, OSError, PermissionError):
        pass

